   134→// splitResponse contains the results of a concurrent data source query - the response and any headers
   135→type splitResponse struct {
   136→	responses backend.Responses
   137→	header    http.Header
   138→}
   139→
   140→// executeConcurrentQueries executes queries to multiple datasources concurrently and returns the aggregate result.
   141→func (s *ServiceImpl) executeConcurrentQueries(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest, queriesbyDs map[string][]parsedQuery) (*backend.QueryDataResponse, error) {
   142→	g, ctx := errgroup.WithContext(ctx)
   143→	g.SetLimit(s.concurrentQueryLimit) // prevent too many concurrent requests
   144→	rchan := make(chan splitResponse, len(queriesbyDs))
   145→
   146→	// Create panic recovery function for loop below
   147→	recoveryFn := func(queries []*simplejson.Json) {
   148→		if r := recover(); r != nil {
   149→			var err error
   150→			s.log.Error("query datasource panic", "error", r, "stack", log.Stack(1))
   151→			if theErr, ok := r.(error); ok {
   152→				err = theErr
   153→			} else if theErrString, ok := r.(string); ok {
   154→				err = errors.New(theErrString)
   155→			} else {
   156→				err = fmt.Errorf("unexpected error - %s", s.cfg.UserFacingDefaultError)
   157→			}
   158→			// Due to the panic, there is no valid response for any query for this datasource. Append an error for each one.
   159→			rchan <- buildErrorResponses(err, queries)
   160→		}
   161→	}
   162→
   163→	// Query each datasource concurrently
   164→	for _, queries := range queriesbyDs {
   165→		rawQueries := make([]*simplejson.Json, len(queries))
   166→		for i := 0; i < len(queries); i++ {
   167→			rawQueries[i] = queries[i].rawQuery
   168→		}
   169→		g.Go(func() error {
   170→			subDTO := reqDTO.CloneWithQueries(rawQueries)
   171→			// Handle panics in the datasource qery
   172→			defer recoveryFn(subDTO.Queries)
   173→
   174→			ctxCopy := contexthandler.CopyWithReqContext(ctx)
   175→			subResp, err := s.QueryData(ctxCopy, user, skipDSCache, subDTO)
   176→			if err == nil {
   177→				reqCtx, header := contexthandler.FromContext(ctxCopy), http.Header{}
   178→				if reqCtx != nil {
   179→					header = reqCtx.Resp.Header()
   180→				}
   181→				rchan <- splitResponse{subResp.Responses, header}
   182→			} else {
   183→				// If there was an error, return an error response for each query for this datasource
   184→				rchan <- buildErrorResponses(err, subDTO.Queries)
   185→			}
   186→			return nil
   187→		})
   188→	}
   189→
   190→	if err := g.Wait(); err != nil {
   191→		return nil, err
   192→	}
   193→	close(rchan)
   194→	resp := backend.NewQueryDataResponse()
   195→	reqCtx := contexthandler.FromContext(ctx)
   196→	for result := range rchan {
   197→		for refId, dataResponse := range result.responses {
   198→			resp.Responses[refId] = dataResponse
   199→		}
   200→		if reqCtx != nil {
   201→			for k, v := range result.header {
   202→				for _, val := range v {
   203→					if !slices.Contains(reqCtx.Resp.Header().Values(k), val) {
   204→						reqCtx.Resp.Header().Add(k, val)
   205→					} else {
   206→						s.log.Warn("skipped duplicate response header", "header", k, "value", val)
   207→					}
   208→				}
   209→			}
   210→		}
   211→	}
   212→
   213→	return resp, nil
   214→}
